mapper.select:
SELECT id, user_id, title, content, content_format, word_count, type, status, is_top, like_count, comment_count, view_count, images, create_time, update_time FROM post WHERE user_id = #{userId} AND is_deleted = 0
AND status = 0
AND status != 0
AND status = #{status}
ORDER BY create_time DESC LIMIT #{offset}, #{size}
